module top_module (
    input clk,
    input d,
    input reset,
    output reg q
);

    // D flip-flop with asynchronous reset logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
        if (reset) begin
            q <= 0;
        end else begin
            q <= d;
        end
    end

endmodule
